var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"흑막은 언제나 절체절명의 타이밍에 등장하는 법.","JPN":"黒幕はいつも絶体絶命のタイミングで登場するもの。","ENG":"The Shadow Group always arrives when all hope seems lost.","TWN":"黑幕總是在千鈞一髮之際登場。"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"어둠의 흑막조장…… 아니, 나나하라 가문연합의 카토리 마사키! 이곳에 강림!","JPN":"闇の黒幕組長……もとい、七原家連合の香取雅紀！　ここに降臨！","ENG":"The Shadow Group's boss– I mean, Nanahara Family Alliance's Katori Masaki is here!","TWN":"黑暗的黑幕組長……不對，是七原家族聯盟的香取雅紀！到此一遊！"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"다행이다. 방송에 나온 위치가 맞았어.","JPN":"よかった。番組に出てた位置で合ってたね。","ENG":"Phew. The broadcasted location was correct.","TWN":"太好了，廣播中說的位置是對的。"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"호오. 결계를 통과하다니. 새로운 샘플이로군.","JPN":"ほお。結界を通過してくるとは。新しいサンプルだな。","ENG":"Ho-oh. Passed the barrier, I see. We have new samples.","TWN":"喔呵，居然能夠越過結界，有新的樣本呢。"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"미나토님? 마사키님?","JPN":"湊様？　雅紀様？","ENG":"Mr. Nayuka? Mr. Katori?","TWN":"南裕夏？雅紀？"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"미안. 늦었지?","JPN":"ごめん。遅くなって。","ENG":"Sorry. We're late, weren't we?","TWN":"抱歉，我們來晚了吧？"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"두 분께선…… 도시에서 인명을 돕느라 못 오시는 것이 아니었나요?","JPN":"お二人は……都市での救命のお仕事でお忙しかったのでは？","ENG":"Weren't you two... preoccupied with helping people within the city?","TWN":"你們……不是忙著在城裡救人嗎？"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"괜찮아. 믿을 수 있는 사람에게 맡기고 오는 길이니까.","JPN":"大丈夫。信用できる人に任せてきたから。","ENG":"It's all right. We entrusted it to someone we have confidence in.","TWN":"沒問題的，我們有找到可靠的人幫忙。"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"믿을 수 있는 사람……?","JPN":"信用できる人……？","ENG":"Have confidence in...?","TWN":"可靠的人……？"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"아키 씨. 이젠 무리예요! 침식체가 줄어들지 않아요! 잡아 먹힌다고요!","JPN":"廣瀬さん。もう無理です！　侵食体が減りません！　私たち食べられちゃいますよ！","ENG":"Ms. Hirose, we have to fall back! The C.O.s just keep coming! We'll get eaten by them at this rate!","TWN":"廣瀨秋，沒辦法啦！侵蝕體根本就沒有減少！我們會被吞掉的！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"버텨요, 민서 양! 민서 양이 잡아 먹히면 니트 따위인 저 혼자선 무리라고요!","JPN":"耐えてください、ヒミコさん！　ヒミコさんが食べられたらニートの私一人では無理です！","ENG":"Hold it, Minseo! If you get consumed, I can't be a freeloader by myself!","TWN":"撐住，旼序！要是你被吞掉的話，只剩我一個人肯定完蛋的啦！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"진짜 그 흑막조라는 사람들 믿을 수 있는 거 맞아요? 나눠준다는 지분의 50%라는 게 얼만지도 모르잖아요!","JPN":"本当にあの黒幕組って人たち、信用できるんですか？　分けてくれるっていう持分の50%ってのもいくらなのかわからないですよ！","ENG":"That Shadow Group person, can we really trust him? We don't even know how much 50% of his shares even is!","TWN":"那個什麼黑幕組的真的可信嗎？說要分給我們50%的股份，也不知道到底是多少！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"틀림없어요. 큰 돈을 아무렇지 않게 맡기는 미나토 씨가 그 비밀조직의 멤버라고요.","JPN":"間違いありません。大金をぽんと預ける湊さんがその秘密組織のメンバーなんですよ。","ENG":"No doubt about it. Minato is a member of that secret organization, and he treats large sums of money as if they were nothing.","TWN":"沒問題的啦，南裕夏可是那個秘密組織的成員，他隨隨便便就交給我一大筆錢欸！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"그러니까 그 사람들 돌아올 때까지 여길 지키면 무위도식의 꿈이 이뤄지는 거예요! 민서 양!","JPN":"ですから、あの人たちが戻ってくるまでここを死守すれば働かずに食べていける夢が叶うんです！　ヒミコさん！","ENG":"So if we hold here until he comes, our dream on an idle life will come true, Minseo!","TWN":"只要能夠堅持到他們回來，那我們遊手好閒的夢想就可以實現咧！旼序！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"목숨 걸고 싸우는 순간부터 무위도식의 꿈은 이미 끝장난 것 같은데요?!","JPN":"命かけて戦う時点でその夢は終わってませんか！？","ENG":"Don’t you think our dreams of living an idle life ended the moment we started fighting for our lives?!","TWN":"從我們出生入死的瞬間開始，遊手好閒的夢想似乎就已經離我們遠去。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"꺄아악, 또 온다!","JPN":"きゃあ、また来た！","ENG":"Kyaaaah! More are coming!","TWN":"啊啊啊，又來啦！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};